import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Tuple

def decode_jwt(token: str, secret: Optional[str] = None, verify: bool = False, 
               algorithms: list = None) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token: JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify signature (default: False for debugging)
        algorithms: List of allowed algorithms (default: ['HS256', 'HS384', 'HS512', 'RS256'])
    
    Returns:
        Tuple of (header, payload) dictionaries
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512']
    
    # Decode header without verification
    header = jwt.get_unverified_header(token)
    
    if verify and secret:
        # Verify and decode
        payload = jwt.decode(token, secret, algorithms=algorithms)
    else:
        # Decode without verification for debugging
        payload = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
    
    return header, payload


def inspect_jwt(token: str, secret: Optional[str] = None, verify: bool = False) -> str:
    """
    Inspect JWT token and return formatted information for debugging.
    
    Args:
        token: JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify signature (default: False)
    
    Returns:
        Formatted string with token information
    """
    try:
        header, payload = decode_jwt(token, secret, verify)
        
        output = []
        output.append("=" * 60)
        output.append("JWT TOKEN INSPECTION")
        output.append("=" * 60)
        
        # Header information
        output.append("\nHEADER:")
        output.append("-" * 60)
        output.append(json.dumps(header, indent=2))
        
        # Payload information
        output.append("\nPAYLOAD:")
        output.append("-" * 60)
        output.append(json.dumps(payload, indent=2))
        
        # Decode timestamps
        output.append("\nTIMESTAMP DETAILS:")
        output.append("-" * 60)
        
        timestamp_fields = {
            'exp': 'Expiration Time',
            'iat': 'Issued At',
            'nbf': 'Not Before'
        }
        
        for field, label in timestamp_fields.items():
            if field in payload:
                timestamp = payload[field]
                dt = datetime.fromtimestamp(timestamp)
                now = datetime.now()
                output.append(f"{label} ({field}): {dt.strftime('%Y-%m-%d %H:%M:%S')}")
                
                if field == 'exp':
                    if dt > now:
                        diff = dt - now
                        output.append(f"  Status: Valid (expires in {diff})")
                    else:
                        diff = now - dt
                        output.append(f"  Status: EXPIRED (expired {diff} ago)")
        
        # Verification status
        output.append("\nVERIFICATION:")
        output.append("-" * 60)
        if verify and secret:
            output.append("Signature: VERIFIED")
        else:
            output.append("Signature: NOT VERIFIED (debugging mode)")
        
        output.append("=" * 60)
        
        return "\n".join(output)
        
    except jwt.ExpiredSignatureError:
        return "ERROR: Token has expired"
    except jwt.InvalidTokenError as e:
        return f"ERROR: Invalid token - {str(e)}"
    except Exception as e:
        return f"ERROR: {str(e)}"


def verify_jwt(token: str, secret: str, algorithms: list = None, 
               audience: Optional[str] = None, issuer: Optional[str] = None) -> Dict[str, Any]:
    """
    Verify JWT token with full validation.
    
    Args:
        token: JWT token string
        secret: Secret key for verification
        algorithms: List of allowed algorithms
        audience: Expected audience claim
        issuer: Expected issuer claim
    
    Returns:
        Decoded payload if valid
    
    Raises:
        jwt.InvalidTokenError: If token is invalid
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256']
    
    options = {}
    kwargs = {'algorithms': algorithms}
    
    if audience:
        kwargs['audience'] = audience
    if issuer:
        kwargs['issuer'] = issuer
    
    payload = jwt.decode(token, secret, **kwargs)
    return payload


# Quick usage functions
def quick_decode(token: str) -> dict:
    """Quick decode without verification - returns payload only"""
    _, payload = decode_jwt(token)
    return payload


def quick_inspect(token: str):
    """Quick inspect and print token details"""
    print(inspect_jwt(token))


def is_expired(token: str) -> bool:
    """Check if token is expired"""
    try:
        _, payload = decode_jwt(token)
        if 'exp' in payload:
            exp_time = datetime.fromtimestamp(payload['exp'])
            return exp_time < datetime.now()
        return False
    except:
        return True